import React, { useState, useEffect } from 'react';
import api from '../services/api'

import Button from '@mui/material/Button';
import { TextField } from 'formik-mui';
import Dialog from '@mui/material/Dialog';
import DialogActions from '@mui/material/DialogActions';
import DialogContent from '@mui/material/DialogContent';
import DialogTitle from '@mui/material/DialogTitle';
import { Formik, Form, Field } from 'formik';


export default function Quartos() {
  const [list, setList] = useState([]);
  const [open, setOpen] = useState(false);
  const [selectedRole, setSelectedRole] = useState({});


  function atualizarLista() {
    api.get('/roles').then(response => {
      setList(response.data)
    }).catch(error => {
      console.log(error);
    });
  }

  useEffect(() => {
    atualizarLista();
  }, []);

  const handleClickConfirmCheckin = () => {
    setOpen(false);
  };

  const handleClickCheckinDialog = (_role) => {
    setSelectedRole(_role);
    setOpen(true);
  };

  const handleClickConfirmCheckout = (id) => {
    api.post("/checkout", { id }).then(() => {
      atualizarLista()
    })
  };

  const handleClose = () => {
    setOpen(false);
  };

  return (
    <>
      <ul>
        {list.map(role => {
          return (
            <div key={role.id}>
              <li>{role.nome} <button disabled={role.usuarios.length > 0} onClick={() => handleClickCheckinDialog(role)}>Check-in</button></li>
              {
                role.usuarios.map(usuario => {
                  return (
                    <div key={usuario.id}> - {usuario.nome} <button onClick={() => handleClickConfirmCheckout(usuario.usuario_role.id)}>Check-out</button></div>
                  )
                })
              }
            </div>
          )
        })}
      </ul>

      <Dialog open={open} onClose={handleClose}>
        <DialogTitle>Realizar Checkin em {selectedRole.nome}</DialogTitle>
        <DialogContent>
          <Formik validateOnBlur
            initialValues={{ nome: '', email: '', telefone: '' }}
            validate={(values) => {
              //alert(JSON.stringify(values))
              const errors = {};
              if (!values.nome) {
                errors.nome = 'Informação requerida';
              }
              return errors;
            }}
            onSubmit={async (values, { setSubmitting }) => {
              await api.post("/checkin", { nome: values.nome, email: values.email, telefone: values.telefone, idRole: selectedRole.id })
              atualizarLista()
              setOpen(false);
              setSubmitting(false);
            }}
          >
            {({ values, submitForm, isSubmitting, touched, errors, setFieldValue, handleChange, handleBlur, isValid }) => (
              <Form>

                <Field
                  component={TextField}
                  type="text"
                  label="Nome"
                  name="nome"
                  fullWidth
                  variant="standard"
                />

                <Field component={TextField}
                  name="email"
                  type="text"
                  label="Email"
                  fullWidth
                  variant="standard"
                />
                <Field component={TextField}
                  name="telefone"
                  type="text"
                  label="Telefone"
                  fullWidth
                  variant="standard"
                />
                <DialogActions>
                  <Button onClick={handleClose}>Cancelar</Button>
                  <Button type="submit" disabled={isSubmitting || !isValid}>Check-in</Button>
                </DialogActions>
              </Form>)}
          </Formik>

        </DialogContent>
      </Dialog>

    </>
  );
};