import React, { useEffect } from "react";
import { useLocation, Navigate } from "react-router-dom";
import TextField from '@mui/material/TextField';
import api from "../services/api"

function useQuery() {
  const { search } = useLocation();
  return React.useMemo(() => new URLSearchParams(search), [search]);
}

export default function Login() {

  useEffect(() => {
    localStorage.setItem('token', token);
    api.get('auth').then(resp => {
      console.log(resp.data)
      window.location = '/acao'
    }).catch(error => {
      if (error.response.status === 401) {
        window.location = '/loginInvalido'
      } else {
        window.location = '/servidorIndisponivel'
      }
    })
  }, [])

  const query = useQuery();
  const token = query.keys().next().value;
  if (token) {
    localStorage.setItem('token', token);
    return <div>Carregando...</div>
  } else {
    return (<div>Informe sua credencial para efetuar login<br /><TextField /></div>)
  }
}
